  ('elementary-0a2fc18c-moex-00222', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '有民眾攜帶寵物蛇搭乘自強號，寵物蛇爬行到車廂屋頂處造成乘客恐慌。嗣後臺鐵表示要依法追究飼主之 責任，並依據法律對行為違反規定的飼主施以處罰，其處罰性質與下列選項何者相同？', '["因故意或過失，不法侵害他人之權利者", "擅自以公開播送方法侵害他人之著作財產權者", "私行拘禁或以其他非法方法，剝奪人之行動自由者", "因違反鐵路法規而處以罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
